classDiagram(name = "LibraryManagement") {
    val library = classOf(name = "Library") {
        attribute(name = "name", type = "String")
    }
    val book = classOf(name = "Book") {
        attribute(name = "title", type = "String")
        attribute(name = "isbn", type = "String")
    }
    val member = classOf(name = "Member") {
        attribute(name = "memberNumber", type = "Int")
        attribute(name = "name", type = "String")
    }
    val loan = classOf(name = "Loan") {
        attribute(name = "loanDate", type = "Date")
        attribute(name = "returnDate", type = "Date")
        attribute(name = "isExtended", type = "Boolean")
        operation(name = "extendLoan")
    }

    association(source = library, target = book) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1..*"); role = "books" } // A Library manages 1 to many Books
        target { multiplicity(spec = "1"); role = "library" } // Each Book belongs to exactly one Library
    }

    association(source = member, target = loan) {
        source { multiplicity(spec = "0..*"); role = "loans" } // A Member can have 0 to many Loans
        target { multiplicity(spec = "1"); role = "borrower" } // Each Loan is for exactly one Member
    }

    association(source = book, target = loan) {
        source { multiplicity(spec = "0..*"); role = "loans" } // A Book can be involved in 0 to many Loans over time
        target { multiplicity(spec = "1"); role = "book" } // Each Loan is for exactly one Book
    }
}

