import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "RobotArmModel") {
    val base = partDef(name = "Base")
    val endEffector = partDef(name = "End Effector")

    val joint = partDef(name = "Joint")
    val revoluteJoint = partDef(name = "Revolute Joint") {
        // Fix: 'specializes' is an unresolved reference. 'generalizes' is a common alternative for inheritance.
        // Assuming generalizes is available in the kUML DSL for partDef specialization.
        generalizes(joint.id)
    }
    val prismaticJoint = partDef(name = "Prismatic Joint") {
        // Fix: Same as above for revoluteJoint.
        generalizes(joint.id)
    }

    val robotArm = partDef(name = "Robot Arm") {
        // Fix: 'multiplicity' as a block inside 'part' is an unresolved reference and causes type mismatch.
        // The error suggests 'KermlMultiplicity' is expected as an argument type for 'multiplicity'.
        // Assuming KermlMultiplicity is a constructor or function that can be called directly.
        part(name = "base", typeId = base.id, multiplicity = KermlMultiplicity(lower = 1, upper = 1))
        part(name = "joint", typeId = joint.id, multiplicity = KermlMultiplicity(lower = 1, upper = 6))
        part(name = "endEffector", typeId = endEffector.id, multiplicity = KermlMultiplicity(lower = 1, upper = 1))
    }

    bdd(name = "Robot Arm BDD") {
        include(base)
        include(endEffector)
        include(joint)
        include(revoluteJoint)
        include(prismaticJoint)
        include(robotArm)
    }
}

