import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "WindTurbineModel") {
    // 1. Declare atomic/leaf Part Definitions first to ensure their IDs are available
    val hub = partDef(name = "Hub")
    val gearbox = partDef(name = "Gearbox")
    val generator = partDef(name = "Generator")
    val nacelleHousing = partDef(name = "Nacelle Housing")
    val pitchControlSystem = partDef(name = "Pitch Control System")
    val yawControlSystem = partDef(name = "Yaw Control System")
    val conditionMonitoringSystem = partDef(name = "Condition Monitoring System")
    val tower = partDef(name = "Tower")

    // 2. Declare abstract base block (Rotor Blade)
    val rotorBlade = partDef(name = "Rotor Blade")

    // 3. Declare specialized Part Definitions.
    // FIX: 'specializes' is a parameter of partDef, not a block statement.
    val gfrpBlade = partDef(name = "GFRP Blade", specializes = rotorBlade.id)
    val cfrpBlade = partDef(name = "CFRP Blade", specializes = rotorBlade.id)

    // 4. Declare composite Part Definitions from bottom up
    val drivetrain = partDef(name = "Drivetrain") {
        part(name = "gearbox", typeId = gearbox.id)
        part(name = "generator", typeId = generator.id)
    }

    val rotor = partDef(name = "Rotor") {
        part(name = "hub", typeId = hub.id)
        // Composition to the abstract Rotor Blade, allowing specific variants to be used in practice
        // FIX: Remove 'isMultiple' parameter as it's not supported by the DSL's 'part' function.
        part(name = "blade", typeId = rotorBlade.id)
    }

    // 5. Declare the top-level composite Part Definition
    val windTurbine = partDef(name = "Wind Turbine") {
        part(name = "rotor", typeId = rotor.id)
        part(name = "drivetrain", typeId = drivetrain.id)
        part(name = "nacelleHousing", typeId = nacelleHousing.id)
        part(name = "pitchControlSystem", typeId = pitchControlSystem.id)
        part(name = "yawControlSystem", typeId = yawControlSystem.id)
        part(name = "cms", typeId = conditionMonitoringSystem.id)
        part(name = "tower", typeId = tower.id)
    }

    // Block Definition Diagram rendering
    bdd(name = "Wind Turbine BDD") {
        include(windTurbine)
        include(rotor)
        include(hub)
        include(rotorBlade)
        include(gfrpBlade)
        include(cfrpBlade)
        include(drivetrain)
        include(gearbox)
        include(generator)
        include(nacelleHousing)
        include(pitchControlSystem)
        include(yawControlSystem)
        include(conditionMonitoringSystem)
        include(tower)
    }
}

import dev.kuml.sysml2.dsl.sysml2Model

sysml2Model(name = "AUTOSAR_ECU_Model") {
    // Hardware Layer Components
    val communicationController = partDef(name = "Communication Controller", isAbstract = true)
    val canController = partDef(name = "CAN Controller") { specializes(communicationController.id) }
    val linController = partDef(name = "LIN Controller") { specializes(communicationController.id) }
    val ethernetController = partDef(name = "Ethernet Controller") { specializes(communicationController.id) }

    val cpuCore = partDef(name = "CPU Core")
    val ram = partDef(name = "RAM")
    val flashMemory = partDef(name = "Flash Memory")

    val microcontroller = partDef(name = "Microcontroller") {
        part(name = "core", typeId = cpuCore.id)
        part(name = "ram", typeId = ram.id)
        part(name = "flash", typeId = flashMemory.id)
        part(name = "canCtrl", typeId = canController.id)
        part(name = "linCtrl", typeId = linController.id)
        part(name = "ethCtrl", typeId = ethernetController.id)
    }

    val hardwareLayer = partDef(name = "Hardware Layer") {
        part(name = "mcu", typeId = microcontroller.id)
    }

    // AUTOSAR BSW Layer Components
    val bswModule = partDef(name = "BSW Module", isAbstract = true)

    val canDriver = partDef(name = "CAN Driver")
    val ethernetDriver = partDef(name = "Ethernet Driver")
    val mcal = partDef(name = "MCAL") {
        specializes(bswModule.id)
        part(name = "canDrv", typeId = canDriver.id)
        part(name = "ethDrv", typeId = ethernetDriver.id)
    }

    val canStack = partDef(name = "CAN Stack")
    val ethernetStack = partDef(name = "Ethernet Stack")
    val communicationStacks = partDef(name = "Communication Stacks") {
        specializes(bswModule.id)
        part(name = "canStk", typeId = canStack.id)
        part(name = "ethStk", typeId = ethernetStack.id)
    }

    val os = partDef(name = "OS")
    val watchdog = partDef(name = "Watchdog")
    val systemServices = partDef(name = "System Services") {
        specializes(bswModule.id)
        part(name = "os", typeId = os.id)
        part(name = "watchdog", typeId = watchdog.id)
    }

    val autosarBswLayer = partDef(name = "AUTOSAR BSW Layer") {
        part(name = "mcal", typeId = mcal.id)
        part(name = "commStacks", typeId = communicationStacks.id)
        part(name = "sysServices", typeId = systemServices.id)
    }

    // Application Layer Components
    val softwareComponent = partDef(name = "Software Component")
    val virtualFunctionalBus = partDef(name = "Virtual Functional Bus")

    val applicationLayer = partDef(name = "Application Layer") {
        part(name = "swc1", typeId = softwareComponent.id)
        part(name = "swc2", typeId = softwareComponent.id)
        part(name = "vfb", typeId = virtualFunctionalBus.id)
    }

    // Top-level ECU
    val ecu = partDef(name = "ECU") {
        part(name = "hardwareLayer", typeId = hardwareLayer.id)
        part(name = "bswLayer", typeId = autosarBswLayer.id)
        part(name = "applicationLayer", typeId = applicationLayer.id)
    }

    bdd(name = "AUTOSAR ECU BDD") {
        include(ecu)
        include(hardwareLayer)
        include(microcontroller)
        include(cpuCore)
        include(ram)
        include(flashMemory)
        include(communicationController)
        include(canController)
        include(linController)
        include(ethernetController)
        include(autosarBswLayer)
        include(bswModule)
        include(mcal)
        include(canDriver)
        include(ethernetDriver)
        include(communicationStacks)
        include(canStack)
        include(ethernetStack)
        include(systemServices)
        include(os)
        include(watchdog)
        include(applicationLayer)
        include(softwareComponent)
        include(virtualFunctionalBus)
    }
}

